import React from 'react';

function BookCard({ book, onSelectBook }) {
  return (
    <div
      onClick={() => onSelectBook(book.id)}
      className="bg-white rounded-xl shadow-lg p-6 cursor-pointer transform transition-transform duration-300 hover:scale-105 hover:shadow-xl border-t-4 border-blue-500"
    >
      <h2 className="text-2xl font-bold text-gray-900 mb-2">{book.title}</h2>
      <p className="text-md text-gray-600 mb-4 font-medium">by {book.author}</p>
      <div className="flex items-center">
        <span className="text-yellow-500 text-lg">⭐</span>
        <span className="ml-2 text-xl font-semibold text-gray-800">{book.rating}</span>
      </div>
    </div>
  );
}

export default BookCard;
